/* Crucial: Ensure the HTML lang attribute is set for the page or relevant elements, e.g., <html lang="en"> */

.article-body {
    hyphens: auto; /* Enable automatic hyphenation */
    text-align: justify; /* Often used with hyphenation for even margins */
    hyphenate-limit-chars: 6 3 3; /* Min chars in word, before hyphen, after hyphen */
    hyphenate-limit-lines: 2; /* Max consecutive lines that can end with a hyphen */
    hyphenate-limit-last: always; /* Allow hyphenation even on the last line of a paragraph */
    word-break: normal; /* Default, works well with hyphens */

    /* Vendor prefixes might still be needed for older browser support */
    -webkit-hyphens: auto;
    -ms-hyphens: auto;
}

/* Example for a specific language with different hyphenation preferences */
html[lang="de"] .article-body {
    hyphens: auto;
    -webkit-hyphens: auto;
    -ms-hyphens: auto;
    hyphenate-limit-chars: 6 2 2; /* More aggressive hyphenation for German */
}
